const blockedTels = { current: {} };


const MAX_PIZZE_ORA = 40;

// ═══ DELIVERY — Una sola fonte di verità ═══
// Quanto costa la consegna a domicilio. Per cambiarlo, modifica solo questo valore.
const DELIVERY_FEE = 2.50;

// delivery_fee per un ordine in base al tipo_consegna. Usare sempre questa funzione.
function deliveryFeeFor(tipoConsegna) {
  return tipoConsegna === "DOMICILIO" ? DELIVERY_FEE : 0;
}

// Totale ordine: somma items + delivery_fee. Usare in UI quando l'ordine non è ancora salvato.
// Per ordini già salvati su DB → leggere o.totale direttamente.
function calcTotale(items, tipoConsegna) {
  const sum = (items || []).reduce((s, i) => s + (Number(i.p)||0) * (Number(i.q)||1), 0);
  return Math.round((sum + deliveryFeeFor(tipoConsegna)) * 100) / 100;
}

// Sconto cliente: applica € fisso o % sul totale finale (items + delivery_fee).
// tipo: "EURO" | "PERCENT" | null   valore: numero (es. 2 per -2€, 5 per -5%)
// Ritorna { totale: post-sconto, importe: € effettivamente scontati }.
// `importe` viene salvato su DB per analytics (Economia: "Stasera ho dato via X€").
// Sorgente unica sia frontend (preview) che backend (autoritativo).
function aplicarDescuento(totaleBase, tipo, valor) {
  const base = Number(totaleBase) || 0;
  const v    = Number(valor)      || 0;
  if (!tipo || v <= 0 || base <= 0) return { totale: base, importe: 0 };
  let importe = 0;
  if (tipo === "EURO")    importe = v;
  if (tipo === "PERCENT") importe = (base * v) / 100;
  if (importe > base) importe = base;
  importe = Math.round(importe * 100) / 100;
  const totale = Math.round((base - importe) * 100) / 100;
  return { totale, importe };
}

